#include<bits/stdc++.h>
using namespace std;
int n,s,t,cnt[1010];
double dis[1010];
bool vis[1010];
const double eps=1e-9;
struct node
{
    int v,type;
    double val;
};
vector<node> mp[1010];
bool spfa(double mid)
{
    for(int i=0;i<=n+1;i++)
    {
        dis[i]=-1e12;
        vis[i]=false;
        cnt[i]=0;
    }
    queue<int> q;
    q.push(n+1);
    dis[n+1]=0;
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        vis[t]=false;
        for(auto i:mp[t])
        {
            int v=i.v;
            double val=i.val;
            if(i.type==1)
            {
                val=log2(val-mid);
            }
            if(i.type==2)
            {
                val=-log2(val+mid);
            }
            if(dis[v]<dis[t]+val)
            {
                dis[v]=dis[t]+val;
                cnt[v]=cnt[t]+1;
                if(cnt[v]>n+2)
                {
                    return true;
                }
                if(!vis[v])
                {
                    vis[v]=true;
                    q.push(v);
                }
            }
        }
    }
    return false;
}
int main()
{
    scanf("%d%d%d",&n,&s,&t);
    double l=0,r=10;
    for(int i=0;i<=n;i++)
    {
        mp[n+1].push_back((node){i,3,0});
    }
    for(int i=1;i<=s;i++)
    {
        int op,a,b;
        double k;
        scanf("%d%d%d%lf",&op,&a,&b,&k);
        mp[b].push_back((node){a,op,k});
        if(op==1)
        {
            r=min(r,k);
        }
    }
    for(int i=1;i<=t;i++)
    {
        int c;
        double x;
        scanf("%d%lf",&c,&x);
        mp[0].push_back((node){c,3,log2(x)});
        mp[c].push_back((node){0,3,-log2(x)});
    }
    double best=0;
    if(!spfa(0))
    {
        printf("-1");
        return 0;
    }
    while(r-l>eps)
    {
        double mid=(l+r)/2.0;
        if(spfa(mid))
        {
            best=mid;
            l=mid+eps;
        }
        else
        {
            r=mid-eps;
        }
    }
    printf("%.7lf",best);
    return 0;
}
